import { Budget } from '../types';

const STORAGE_KEY = 'auto_pinturas_budgets';
const ID_COUNTER_KEY = 'auto_pinturas_id_counter';

export const db = {
  getAll: (): Budget[] => {
    try {
      const data = localStorage.getItem(STORAGE_KEY);
      return data ? JSON.parse(data) : [];
    } catch (e) {
      console.error("Error reading from DB", e);
      return [];
    }
  },

  getById: (id: number): Budget | undefined => {
    const all = db.getAll();
    return all.find((b) => b.id === id);
  },

  save: (budget: Omit<Budget, 'id'> | Budget): Budget => {
    const all = db.getAll();
    let newBudget: Budget;

    if ('id' in budget) {
      // Update existing
      const index = all.findIndex((b) => b.id === budget.id);
      if (index >= 0) {
        all[index] = budget as Budget;
        newBudget = budget as Budget;
      } else {
        // Fallback if ID not found, treat as new (shouldn't happen often)
        newBudget = { ...budget, id: db.getNextId() } as Budget;
        all.push(newBudget);
      }
    } else {
      // Create new
      newBudget = { ...budget, id: db.getNextId() };
      all.push(newBudget);
    }

    localStorage.setItem(STORAGE_KEY, JSON.stringify(all));
    return newBudget;
  },

  delete: (id: number) => {
    const all = db.getAll();
    const filtered = all.filter((b) => b.id !== id);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(filtered));
  },

  getNextId: (): number => {
    const current = parseInt(localStorage.getItem(ID_COUNTER_KEY) || '1000', 10);
    const next = current + 1;
    localStorage.setItem(ID_COUNTER_KEY, next.toString());
    return next;
  }
};

