  const handleServiceChange = (part: string, field: keyof ServiceSelection) => {
    setServices(prev => ({
      ...prev,
      [part]: {
        ...prev[part],
        [field]: !prev[part]?.[field]
      }
    }));
  };

  const handlePartChange = (id: string, field: keyof PartItem, value: string | number) => {
    setParts(prev => prev.map(item => 
      item.id === id ? { ...item, [field]: value } : item
    ));
  };

  const addPartRow = () => {
    setParts(prev => [...prev, { id: Date.now().toString(), description: '', value: 0 }]);
  };

  const removePartRow = (id: string) => {
    if (parts.length > 1) {
      setParts(prev => prev.filter(item => item.id !== id));
    } else {
      // Clear instead of remove if only one
      setParts([{ id: Date.now().toString(), description: '', value: 0 }]);
    }
  };

  const calculateTotal = () => {
    return parts.reduce((acc, item) => acc + (Number(item.value) || 0), 0);
  };

  const handleSave = () => {
    const total = calculateTotal();
    const budgetToSave = {
      ...(budgetId ? { id: budgetId } : {}),
      clientData,
      services,
      parts,
      observations,
      createdAt: existingBudget?.createdAt || Date.now(),
      totalValue: total
    };

    const saved = db.save(budgetToSave as Budget);
    setBudgetId(saved.id);
    alert(`Orçamento nº ${saved.id} salvo com sucesso!`);
  };

  const handlePrint = () => {
    window.print();
  };

  const handleGeneratePDF = async () => {
    if (contentRef.current) {
      // Temporarily simplify styling issues for canvas capture
      const canvas = await html2canvas(contentRef.current, {
        scale: 2, // Higher quality
        useCORS: true,
        logging: false
