                    <button 
                      onClick={() => {
                        if(window.confirm('Tem certeza que deseja excluir?')) onDelete(budget.id);
                      }}
                      className="text-red-500 hover:text-red-700"
                      title="Excluir"
                    >
                      <Trash2 size={18} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

