import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

interface BudgetFormProps {
  existingBudget?: Budget | null;
  onClose: () => void;
}

const emptyServiceSelection: ServiceSelection = {
  funil: false,
  pintura: false,
  retoq: false,
  martel: false,
  partDescription: '',
  partPrice: 0
};

